sql:
SELECT college_name, number_of_students
FROM colleges
WHERE number_of_students > (SELECT AVG(number_of_students) FROM colleges);

SELECT * 
FROM faculty 
WHERE experience = (
    SELECT MAX(experience) 
    FROM faculty
);

SELECT type_of_facility, MAX(year_of_establishment) AS most_recent, MIN(year_of_establishment) AS oldest
FROM infrastructures
GROUP BY type_of_facility;

SELECT COUNT(*) AS facility_count
FROM infrastructures
WHERE college_id = 1;

SELECT college_name, state, city
FROM colleges
WHERE number_of_students = (SELECT MAX(number_of_students) FROM colleges);

SELECT college_name, nirf_score
FROM colleges
WHERE nirf_score = (SELECT MAX(nirf_score) FROM colleges);
